local LModel = LModel
------------------------------------------------------------------
---@class ModelPower:LModel
local ModelPower = LxClass("ModelPower",LModel)

ModelPower.MAIN = 0
ModelPower.FORMATION = 1
ModelPower.HERO = 2

------------------------------------------------------------------
function ModelPower:ModelPower()

end

--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelPower:OnModelInit()
    self:ModelNetMsgRecv(LProtoIds.PowerShowResp, function(...)
        self:OnPowerShowResp(...)
    end)
end

--在协议数据处理完之后需要调用finish
function ModelPower:OnModelRequest()
    self._powerTable={}
    self:ModelFinish()
end


function ModelPower:OnPowerShowResp(pb)
    local maxPower = self:GetMaxMainPower()

    local showType = pb.type
    local _powers = pb.powers
    for i, v in ipairs(_powers) do
        local key = v.key
        local power = v.power
        power = math.floor(power)
        self:SavePower(showType,key,power)
        FireEvent(EventNames.ON_POWER_CHANGE,showType,key,power)
    end
    if showType == ModelPower.MAIN then
        FireEvent(EventNames.ON_DREAM_FOUNTAIN)
    end

    local newMaxPower = self:GetMainCityPower()
    if newMaxPower> maxPower then
        FireEvent(EventNames.ON_MAIN_MAX_POWER_CAHNGE,newMaxPower)
    end
end

-----------------------------------------------
---set

function ModelPower:SavePower(type,key,power)
    local temp= self._powerTable[type]
    if not temp then
        temp={}
        self._powerTable[type]=temp
    end
    temp[key]= power
end

function ModelPower:SaveFormationPower(key,power)
    local temp= self._powerTable[ModelPower.FORMATION]
    if not temp then
        temp={}
        self._powerTable[ModelPower.FORMATION]=temp
    end
    temp[tostring(key)]= power
end


-----------------------------------------------
---get
function ModelPower:GetFormationPower(combatType)

    if combatType == LCombatTypeConst.COMBAT_MAIN then
        return self:GetMainCityPower()
    end

    local temp = self._powerTable[ModelPower.FORMATION]
    if temp then
        local power = temp[tostring(combatType)]
        power = LUtil.ToInteger(power)
        return power
    end

    return 0
end

function ModelPower:GetMainCityPower()
    local temp = self._powerTable[ModelPower.MAIN]
    if not temp then return 0 end
    local combatType = LCombatTypeConst.COMBAT_MAIN
    local power = temp[tostring(combatType)]
    power = math.floor(tonumber(power))
    return power
end

function ModelPower:GetMainPower()
    local temp = self._powerTable[ModelPower.MAIN]
    if temp then
        local combatType = LCombatTypeConst.COMBAT_MAIN
        local power = temp[tostring(combatType)]
        power = math.floor(tonumber(power))
        return power
    else
        return math.floor(tonumber(gModelPlayer:GetPlayerFightPower()))
    end

end

function ModelPower:GetMaxMainPower()
    if not self._maxMainPower then
        self._maxMainPower = gModelPlayer:GetDefaultMaxPower()
    end

    local maincityPower = self:GetMainCityPower() or 0

    self._maxMainPower = math.max(self._maxMainPower,maincityPower)
    self._maxMainPower = math.floor(self._maxMainPower)
    return self._maxMainPower
end



--清理工作
--停止计时器之类的
function ModelPower:OnModelClear()

end

return ModelPower